// docs/MOTION_PHILOSOPHY.md
/*
## Motion principles

1. **Intent first** — every animation answers a 'why'
2. **Communicate, don't decorate** — motion that doesn't communicate is noise
3. **Compositor-only** — transform + opacity; no layout properties
4. **Bounded** — short for routine, longer reserved for hero moments
5. **Match the moment** — settle for serious, snap for confirmation, spring for play
6. **Respect the user** — prefers-reduced-motion is non-negotiable
7. **Test on cheap devices** — 60fps on $200 Android or it's not done
8. **System over snowflakes** — tokens for duration, easing, spring physics
9. **Audit regularly** — animations that lost purpose get retired
10. **Craft** — motion is the difference between an app that works and an app that delights
*/

// motion-system.ts
export const DURATION = {instant: 0.15, routine: 0.25, deliberate: 0.4, hero: 0.8};
export const EASING = {
  settle: [0.4, 0, 0.2, 1],
  snap: [0.25, 0.46, 0.45, 0.94],
  emphasized: [0.2, 0, 0, 1]
};
export const SPRING = {
  gentle: {type: 'spring', damping: 30, stiffness: 200},
  snappy: {type: 'spring', damping: 20, stiffness: 400},
  bouncy: {type: 'spring', damping: 12, stiffness: 300}
};
